import { writeOutput } from "./codegen";

const DOCS_URL = "https://developers.explorium.ai/reference/introduction";
const PLACEHOLDER_VALUE =
  "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSafe";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Explorium API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:explorium",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const exploriumFirewall = {",
    '  name: "explorium",',
    '  description: "Explorium API",',
    "  placeholders: {",
    `    EXPLORIUM_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.explorium.ai",',
    "      auth: {",
    "        headers: {",
    '          api_key: "${{ secrets.EXPLORIUM_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Explorium firewall config...");
  const ts = generateTypeScript();
  writeOutput("explorium", ts, import.meta.dirname);
}
